sap.ui.predefine("ui5/vizframe/app/utils/StaticChatMock", [],function(){"use strict";var e=[{test:/\b(start|startseite|home|hauptseite|zurück)\b/i,reply:'{"action":"navigate","route":"main"}'},{test:/\b(r2r|record.to.report)\b/i,reply:'{"action":"navigate","route":"r2r"}'},{test:/\b(rtr|recruit.to.retire)\b/i,reply:'{"action":"navigate","route":"rtr"}'},{test:/\b(s2p|source.to.pay)\b/i,reply:'{"action":"navigate","route":"s2p"}'},{test:/\b(d2o|design.to.operate)\b/i,reply:'{"action":"navigate","route":"d2o"}'},{test:/\b(l2c|lead.to.cash)\b/i,reply:'{"action":"navigate","route":"l2c"}'},{test:/\b(projekt|project|über das|about)\b/i,reply:'{"action":"navigate","route":"project"}'},{test:/\b(hallo|hi|hey|moin|guten\s*(morgen|tag|abend))\b/i,reply:"Hallo! Ich bin dein KI-Assistent für dieses Dashboard.\n\nIch helfe bei den Prozessen (R2R, RtR, S2P, D2O, L2C), den Kacheln und KPIs. Wobei darf ich helfen?"},{test:/\b(kachel|kackel|tile|oben links|oben rechts|mitte oben|links oben|rechts oben)\b/i,reply:"Die Startseite hat 5 Prozesskacheln in 2 Reihen:<br><br><strong>Reihe 1 (oben, je 1/3):</strong><br>• Links: <strong>Recruit to Retire (RtR)</strong> – Balkendiagramm<br>• Mitte: <strong>Record to Report (R2R)</strong> – Kreisdiagramm<br>• Rechts: <strong>Source to Pay (S2P)</strong> – Donut-Diagramm<br><br><strong>Reihe 2 (unten, je 1/2):</strong><br>• Links: <strong>Design to Operate (D2O)</strong> – Liniendiagramm<br>• Rechts: <strong>Lead to Cash (L2C)</strong> – Balkendiagramm<br><br>Klick auf eine Kachel für die Detailseite!"},{test:/\b(was ist|erkl|bedeutet).*(r2r|record)\b/i,reply:"<strong>Record to Report (R2R)</strong> ist der Finanz-Abschlussprozess:\nBuchungen → Abstimmung → Abschluss → Bericht.\n\nKPIs: Abschlussqualität, Buchungsvolumen, Fehlerquote."},{test:/\b(was ist|erkl|bedeutet).*(rtr|recruit)\b/i,reply:"<strong>Recruit to Retire (RtR)</strong> umfasst alle HR-Prozesse:\nRecruiting → Onboarding → Entwicklung → Abrechnung.\n\nKPIs: Time-to-Hire, Fluktuationsrate, Headcount."},{test:/\b(was ist|erkl|bedeutet).*(s2p|source|einkauf)\b/i,reply:"<strong>Source to Pay (S2P)</strong> ist der Einkaufsprozess:\nBedarf → Lieferant → Bestellung → Rechnung.\n\nKPIs: Einkaufsvolumen, Lieferantenperformance, Durchlaufzeit."},{test:/\b(was ist|erkl|bedeutet).*(d2o|design|produk)\b/i,reply:"<strong>Design to Operate (D2O)</strong> umfasst den Produktentstehungsprozess:\nDesign → Produktion → Qualität → Betrieb.\n\nKPIs: Time-to-Market, OEE, Ausschussrate."},{test:/\b(was ist|erkl|bedeutet).*(l2c|lead|cash|vertrieb)\b/i,reply:"<strong>Lead to Cash (L2C)</strong> ist der Vertriebsprozess:\nLead → Angebot → Auftrag → Zahlung.\n\nKPIs: Conversion Rate, Umsatz, DSO."},{test:/\b(kpi|kennzahl|daten|zahlen|metr)\b/i,reply:"Auf <strong>GitHub Pages</strong> kommen die Diagramme aus den gleichen <strong>Demo-JSON-Dateien</strong> wie lokal im Mock – ohne echtes SAP-Backend."},{test:/\bwas\s+kannst\s+du\s+alles\b/i,reply:"Ich erkläre die App und die Geschäftsprozesse, beantworte Fragen zu Kacheln und KPIs und wechsle die Seite, wenn du es ausdrücklich möchtest (z. B. „Gehe zur Startseite“ / „Navigiere zu L2C“).\n\n(Hinweis: Auf GitHub Pages läuft nur die Offline-Simulation – keine echte KI.)"},{test:/\b(hilfe|help|was kannst|was kannst du|was kann|fähigkeit)\b/i,reply:"Ich erkläre die App und die Geschäftsprozesse, beantworte Fragen zu Kacheln und KPIs und wechsle die Seite, wenn du es ausdrücklich möchtest (z. B. „Gehe zur Startseite“ / „Navigiere zu L2C“).\n\n(Hinweis: Auf GitHub Pages läuft nur die Offline-Simulation – keine echte KI.)"}];var t=/\b(wetter|fu(ß|ss)ball|bundesliga|champions|handball|tennis|basketball|hockey|formel\s*1|olymp|wm\s+20|em\s+20|sportler|politik|bundestag|bundeskanzler|kanzler|wahl|partei|präsident|horoskop|bitcoin|krypto|aktien|netflix|film|serie|musikcharts|rezept|dating)\b/i;var r="Dazu kann ich hier nichts sagen – ich unterstütze nur bei <strong>dieser App</strong> und den <strong>dargestellten Prozessen</strong>.";function n(n){var s=(n||"").trim();for(var i=0;i<e.length;i++){if(e[i].test.test(s)){return e[i].reply}}if(t.test(s)){return r}return"Auf GitHub Pages ist kein Chat-Backend verfügbar. Lokal mit <code>npm run start</code> und API-Key antwortet die echte KI.\n\n"+"Offline gilt: nur diese App und die Prozesse im Dashboard. Schreib <strong>Hilfe</strong> für eine Kurzübersicht."}return{getReply:n}});
